import{_ as a,o as t,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Self-Serve Update","description":"","frontmatter":{"title":"Self-Serve Update","slug":"self-serve-gating"},"headers":[],"relativePath":"account-hub/self-serve-gating.md","filePath":"account-hub/self-serve-gating.md"}'),n={name:"account-hub/self-serve-gating.md"};function s(d,e,l,o,c,h){return t(),i("div",null,[...e[0]||(e[0]=[r(`<p>In March of 2023, Branch introduced self-serve usage for newly created apps that included Branch linking and Ads for free under <strong>10K MAUs</strong> when you enter a credit card. Today, Branch is limiting access to creating Branch Links and certain Dashboard pages/configurations until a credit card is entered for a new Branch app.</p><h2 id="dashboard-links-reporting" tabindex="-1">Dashboard Links &amp; Reporting <a class="header-anchor" href="#dashboard-links-reporting" aria-label="Permalink to &quot;Dashboard Links &amp; Reporting&quot;">​</a></h2><p>In the Branch Dashboard, unless a credit card is entered, the following features will be locked:</p><table tabindex="0"><thead><tr><th><a href="./ad-links.html">Ad Links</a></th><th><a href="./create-quick-links.html">Short Links</a></th><th><a href="./branch-summary-page.html">Summary</a></th></tr></thead><tbody><tr><td>Create Ad Links</td><td>Create Short Links</td><td>View Summary Analytics</td></tr><tr><td>Manage Ad Links</td><td>Manage Short Links</td><td>-</td></tr></tbody></table><p>Accessing a Dashboard feature without a credit card entered for that Branch app will result in the following prompt:</p><hr><h2 id="dynamic-link-redirection" tabindex="-1">Dynamic Link Redirection <a class="header-anchor" href="#dynamic-link-redirection" aria-label="Permalink to &quot;Dynamic Link Redirection&quot;">​</a></h2><p>Adding <a href="./creating-a-deep-link.html">redirection query parameters</a> to dynamic links (Short or Long Links) is disabled.</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Example</th></tr></thead><tbody><tr><td>Short Link</td><td><code>https://example.app.link/fzmLEhobLD?$ios_url=https%3A%2F%2Fbranch.io%2F</code></td></tr><tr><td>Long Link</td><td><code>https://example.app.link/?foo=bar&amp;baz=456&amp;$fallback_url=https%3A%2F%2Fbranch.io%2F</code></td></tr></tbody></table><hr><h2 id="branch-redirects-configuration" tabindex="-1">Branch Redirects Configuration <a class="header-anchor" href="#branch-redirects-configuration" aria-label="Permalink to &quot;Branch Redirects Configuration&quot;">​</a></h2><p>For Branch <a href="./configure-default-link-behaviors.html">Redirects Configuration</a>, unless a credit card is entered, the following settings are disabled:</p><ul><li>Default URL Redirect</li><li>Android Redirects</li><li>iOS Redirects</li><li>Desktop Default</li><li>MacOS Redirect</li><li>Windows Redirect</li><li>Amazon Fire Redirects</li><li>iPad Redirects</li><li>Android Tablet Redirects</li><li>WeChat Redirects</li></ul><hr><h2 id="sdks-apis" tabindex="-1">SDKs &amp; APIs <a class="header-anchor" href="#sdks-apis" aria-label="Permalink to &quot;SDKs &amp; APIs&quot;">​</a></h2><p>All SDKs and specific APIs will be limited in their ability to create links and update Branch App configurations:</p><table tabindex="0"><thead><tr><th><a href="./native-sdks-overview.html">SDKs</a></th><th><a href="./deep-linking-api.html">Deep Linking API</a></th><th><a href="./app-api.html">App API</a></th></tr></thead><tbody><tr><td>All Link Create methods</td><td>All Link Create requests</td><td>Update config request</td></tr></tbody></table><p>Making a call to any of the above methods/requests without a credit card entered for that Branch app will result in the following error response:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;error&quot;: {</span></span>
<span class="line"><span>    &quot;message&quot;: &quot;Access denied&quot;,</span></span>
<span class="line"><span>    &quot;code&quot;: 403</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,19)])])}const f=a(n,[["render",s]]);export{u as __pageData,f as default};
